import Foundation

enum NetworkError: Error {
    case invalidResponse
}

class NetworkManager {
    
    static let shared = NetworkManager()
    
    private var session: URLSession
    
    init() {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForResource = 30
        configuration.waitsForConnectivity = true
        self.session = URLSession(configuration: configuration)
    }
    
    enum Endpoint {
        case user(username: String)
        case login(username: String, password: String)
        
        var url: URL? {
            guard let apiURL = URL(string: "https://api.example.com") else { return nil }
            switch self {
            case .user(let username):
                return URL(string: "\(apiURL)/users/\(username)", relativeTo: apiURL)
            case .login(let username, _):
                return URL(string: "\(apiURL)/login", relativeTo: apiURL)
            }
        }
    }
    
    func performGET(endpoint: Endpoint, completion: @escaping (Result<Data, NetworkError>) -> Void) {
        guard let url = endpoint.url else { completion(.failure(.invalidResponse)); return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.invalidResponse))
                return
            }
            
            completion(.success(data))
        }.resume()
    }
    
    func performPOST(endpoint: Endpoint, data: Data, completion: @escaping (Result<Data, NetworkError>) -> Void) {
        guard let url = endpoint.url else { completion(.failure(.invalidResponse)); return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = data
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.invalidResponse))
                return
            }
            
            completion(.success(data))
        }.resume()
    }
}